-- Create Estúdio Paisagismo area with Nathália Cavalcante as leader
INSERT INTO areas (name, companyName, status) VALUES ('Estúdio Paisagismo', 'Grupo E-sol', 'active')
ON DUPLICATE KEY UPDATE name = VALUES(name);

-- Get the area ID
SET @paisagismo_area_id = (SELECT id FROM areas WHERE name = 'Estúdio Paisagismo' LIMIT 1);

-- Get Nathália Cavalcante's ID for leader
SET @nathalia_id = (SELECT id FROM users WHERE email = 'nathalia.cavalcante@grupoesol.com.br' LIMIT 1);

-- Update area leader
UPDATE areas SET leaderId = @nathalia_id WHERE id = @paisagismo_area_id;

-- Create Jhemilly Viana user
INSERT INTO users (openId, name, email, loginMethod, role, appRole, areaId, leaderId, passwordHash, mustChangePassword, status, lastSignedIn)
VALUES (
  CONCAT('local_', UNIX_TIMESTAMP(), '_jhemilly'),
  'Jhemilly Viana',
  'jhemilly.viana@grupoesol.com.br',
  'email',
  'user',
  'employee',
  @paisagismo_area_id,
  @nathalia_id,
  '$2a$10$LhJxGxJ8xGxJ8xGxJ8xGxOeGxJ8xGxJ8xGxJ8xGxJ8xGxJ8xGxJ',
  1,
  'active',
  NOW()
)
ON DUPLICATE KEY UPDATE name = VALUES(name);

